class Solution:
  def solve(self, port_mappings: str) -> bool:
    # Split the input string into individual port mappings
    mappings = port_mappings.split(',')

    # Iterate over each port mapping
    for mapping in mappings:
      # Split the port mapping into container-port and host-port
      containerPort, hostPort = mapping.split(':')

      # Check if the host-port is a valid port number
      if int(hostPort) < 0 or int(hostPort) > 32767:
        return False

    # If all host-ports are valid, return True
    return True
